INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Relance commerciale adaptée aux complexes hôteliers', 'Formation sur les techniques de relance commerciale adaptées aux complexes hôteliers pour optimiser la fidélisation et conquérir de nouveaux clients.', 5, 200000.00, 'entreprise', '2026-02-10', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Maîtriser les techniques de relance commerciale spécifiques au secteur hôtelier\n• Identifier et cibler les clients à relancer\n• Développer des stratégies de prospection adaptées aux complexes hôteliers\n• Utiliser les outils digitaux et CRM pour suivre les clients et prospects\n• Optimiser la performance commerciale et augmenter le chiffre d’affaires\n\n--- OBJECTIFS DÉTAILLÉS ---\nMaîtriser les techniques de relance commerciale dans le secteur hôtelier, identifier et cibler les clients à relancer, développer des stratégies de prospection adaptées, utiliser les outils digitaux et CRM et optimiser la performance commerciale.\n\n--- PRÉREQUIS ---\nExpérience préalable en vente ou relation client souhaitée, idéalement dans le secteur hôtelier.\n\n--- CONTENU ---\nModule 1 : Introduction à la relance commerciale dans le secteur hôtelier\nModule 2 : Préparation et segmentation des clients à relancer\nModule 3 : Techniques de relance et communication adaptées\nModule 4 : Prospection et recherche de nouveaux marchés hôteliers\nModule 5 : Stratégies de fidélisation et relance combinées\nModule 6 : Utilisation des outils numériques et CRM\nModule 7 : Atelier final – Plan d’action commercial pour complexes hôteliers\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nCommerciaux, responsables marketing et commerciaux, chargés de clientèle et managers dans le secteur hôtelier.\n\n--- MÉTHODES ---\nPrésentations interactives, études de cas, mises en situation, ateliers pratiques, jeux de rôle et exercices d’analyse de marché hôtelier.\n\n--- SUPPORTS ---\nCRM, outils digitaux de prospection, scripts de relance, modèles de suivi client, supports PDF et slides.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
